lessons.example:
def dividir(a, b):
    try:
        return a / b
    except ZeroDivisionError:
        return 'não é possível dividir por zero'

print(dividir(10, 2))   # 5.0
print(dividir(10, 0))   # não é possível dividir por zero

def converter(texto):
    try:
        return int(texto)
    except ValueError:
        return None

print(converter('42'))   # 42
print(converter('abc'))  # None (não quebra o programa)

def idade_valida(idade):
    if idade < 0:
        raise ValueError('idade não pode ser negativa')
    return idade

try:
    idade_valida(-5)
except ValueError as erro:
    print(f'erro: {erro}')
finally:
    print('validação concluída')

